1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type Damage = { itemType: string; amount: number };
9	type Incident = { cause?: string; damages: Damage[] };
10	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
11	type Step = QuoteStep | ClaimStep;
12	type Customer = { yearsWithMHPCO: number };
13	type Scenario = { customer: Customer; steps: Step[] };
14	type QuoteResult = { premium: number };
15	type ClaimResult = { payout: number; remainingCap: number };
16	type StepResult = QuoteResult | ClaimResult;
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const CURSE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const LOYALTY_RATE = 0.2;
24	const LOYALTY_THRESHOLD = 2;
25	const FOLLOWUP_RATE = 0.15;
26	const COMPONENT_BASE_PREMIUM = 25;
27	const COMPONENT_INSURANCE_VALUE = 250;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE_PREMIUM = 60;
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	};
39	
40	const INSURANCE_VALUES: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	};
46	
47	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
48	
49	const componentGroupBase = (count: number): number =>
50	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
51	
52	const countByType = (items: Item[]): Map<string, number> =>
53	  items.reduce(
54	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
55	    new Map<string, number>(),
56	  );
57	
58	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
59	const itemInsuranceValue = (item: Item): number =>
60	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : INSURANCE_VALUES[item.type];
61	
62	const componentsBaseTotal = (components: Item[]): number =>
63	  [...countByType(components).values()].reduce(
64	    (sum, count) => sum + componentGroupBase(count),
65	    0,
66	  );
67	
68	const partitionByComponent = (items: Item[]): { mainItems: Item[]; components: Item[] } =>
69	  items.reduce<{ mainItems: Item[]; components: Item[] }>(
70	    (acc, item) => {
71	      (isComponent(item) ? acc.components : acc.mainItems).push(item);
72	      return acc;
73	    },
74	    { mainItems: [], components: [] },
75	  );
76	
77	const mainItemsBaseTotal = (items: Item[]): number =>
78	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
79	
80	const policyBase = (items: Item[]): number => {
81	  const { mainItems, components } = partitionByComponent(items);
82	  return mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
83	};
84	
85	const insuranceSum = (items: Item[]): number =>
86	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
87	
88	const isCursed = (item: Item): boolean => item.cursed === true;
89	const isHighlyEnchanted = (item: Item): boolean =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
91	
92	const itemSurcharge = (item: Item): number => {
93	  if (isComponent(item)) return 0;
94	  const base = itemBasePremium(item);
95	  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
96	  return base * rate;
97	};
98	
99	const itemSurchargesTotal = (items: Item[]): number =>
100	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
101	
102	const isLoyal = (customer: Customer): boolean => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
103	
104	const loyaltyDiscount = (base: number, customer: Customer): number =>
105	  isLoyal(customer) ? base * LOYALTY_RATE : 0;
106	
107	type Policy = {
108	  items: Item[];
109	  remainingCap: number;
110	};
111	
112	const computeQuote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
113	  const base = policyBase(step.items);
114	  const surcharges = itemSurchargesTotal(step.items);
115	  const firstInsurance = base * FIRST_INSURANCE_RATE;
116	  const loyalty = loyaltyDiscount(base, customer);
117	  const followup = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
118	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followup) + PROCESSING_FEE;
119	  return { premium };
120	};
121	
122	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
124	
125	const computeDamagePayout = (damage: Damage, item: Item): number => {
126	  const reimbursable =
127	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
128	      ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
129	      : damage.amount;
130	  return Math.max(0, reimbursable - DEDUCTIBLE);
131	};
132	
133	const computeClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
134	  const policy = policies.get(step.policy)!;
135	  const grossPayout = step.incident.damages.reduce(
136	    (sum, d) => sum + computeDamagePayout(d, policy.items.find((i) => i.type === d.itemType)!),
137	    0,
138	  );
139	  const payout = Math.min(grossPayout, policy.remainingCap);
140	  policy.remainingCap -= payout;
141	  return { payout, remainingCap: policy.remainingCap };
142	};
143	
144	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
145	  const policies = new Map<number, Policy>();
146	  let quoteIndex = 0;
147	  const results = scenario.steps.map((step, stepIndex) => {
148	    if (step.op === "quote") {
149	      const result = computeQuote(step, scenario.customer, quoteIndex);
150	      policies.set(stepIndex, {
151	        items: step.items,
152	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
153	      });
154	      quoteIndex += 1;
155	      return result;
156	    }
157	    return computeClaim(step, policies);
158	  });
159	  return { results };
160	};
